#include<bits/stdc++.h>
using namespace std;
const int maxxx=1e5+6;
long long n,a[maxxx],f[maxxx],ans=-12342342;
vector <long long> e[maxxx];
void dfs(long long u,long long fa)
{
	f[u]=a[u];
	for(long long i=0;i<e[u].size();i++){
		long long t=e[u][i];
		if(t!=fa){
			dfs(t,u);
			if(f[t]>0){
				f[u]+=f[t];
			}
		}
	}
}
int main(){
	cin>>n;
	for(long long i=1;i<=n;i++){
		cin>>a[i];
	}
	for(long long i=1;i<n;i++){
		long long u,v;
		cin>>u>>v;
		e[u].push_back(v);
		e[v].push_back(u);
	}
	dfs(1,0);
	for(long long i=1;i<=n;i++){
		ans=max(ans,f[i]);
	}
	cout<<max(ans,0ll);
	return 0;
}
